import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as n,a as t}from"./app-667ea0d6.js";const l="/assets/images/vasvari/View-Loading-Without-Dependency-Injection.webp",s={},o=t(`<h1 id="fxml-dependency-injection-and-controller-initialisation" tabindex="-1"><a class="header-anchor" href="#fxml-dependency-injection-and-controller-initialisation" aria-hidden="true">#</a> FXML Dependency Injection and Controller Initialisation</h1><p>Mint minden másban, itt is vannak különböző típusú függőség injektálások, és ha manuálisan szeretnéd irányítani a folyamatot a reflexió használatával, az bonyolulttá válhat. De ez még nem jelenti azt, hogy ezt kötelezően meg kell tenni. Valójában hatalmas funkcionalitásnövekedést érhetünk el a reflexió egyáltalán való használata nélkül is.</p><p>A függőségi injektálás nehéznek tűnik, de valójában egyáltalán nem az. Tulajdonképpen a JavaFX-ben van pár beépített függőségi injektálás, ha tudod, hogyan kell használni.</p><p>Mint bármi másnál, a függőségi injektálásnak is vannak különböző típusai, és ha kézzel akarod irányítani a folyamatot a reflexió segítségével, akkor ez bonyolulttá válhat. De ez nem jelenti azt, hogy muszáj is. Valójában hatalmas funkcionalitásnövekedést érhetünk el úgy is, hogy egyáltalán nem használunk reflexiót.</p><h3 id="mi-az-a-dependency-injection" tabindex="-1"><a class="header-anchor" href="#mi-az-a-dependency-injection" aria-hidden="true">#</a> Mi az a Dependency Injection?</h3><p>A <strong>Dependency Injection</strong> egy olyan tervezési minta, amely az objektum létrehozásának felelősségét eltávolítja a hívó osztálytól. Ezt azzal éri el, hogy létrehoz egy második osztályt - az Injektort -, amely képes átadni az objektumnak azt, amire szüksége van.</p><p>A függőség injektálása a <strong>JavaFX</strong> nézet létrehozásában úgy valósítható meg, hogy egy <code>FXMLLoader</code> objektumot ellátunk egy egyéni metódussal vagy erőforrással, amelyet a vezérlők létrehozásához használhatunk. A <code>FXMLLoader</code> beinjektálja a szükséges függőségeket a <code>Controller</code>-be, és visszaadja azt a hívó osztálynak. Ezeket a metódusokat és erőforrásokat az <code>FXMLLoader</code> meghívásakor, vagy előre betöltött kezelőosztályokkal lehet biztosítani.</p><p>Végig fogunk menni két módszeren, hogy testre szabhassuk a FXMLLoader-t, és lehetőséget adjunk neki az információ &quot;<em>beinjektálására</em>&quot; a vezérlőinkbe:</p><ol><li><p><strong>Konstruktor injektálás (Constructor Injection):</strong> Testre szabhatjuk a vezérlőnket azzal, hogy az adatokat beinjektáljuk a konstruktorba, amikor létrejön.</p></li><li><p><strong>Mezőinjektálás (Field Injection):</strong> Mezőket injektálhatunk a vezérlőbe a gépen található resource fájlok alapján.</p></li></ol><p>Végül mindent beállítunk az alkalmazás életcikluskezelő osztályaként. Valójában ennek az anyagnak a végére képesek leszünk egy <code>Controller</code> és egy <code>View</code> beállítására egyetlen sor kóddal.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">Parent</span> root <span class="token operator">=</span> <span class="token class-name">InjectionManager</span><span class="token punctuation">.</span><span class="token function">load</span><span class="token punctuation">(</span><span class="token string">&quot;/sample.fxml&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="ha-dependency-injection-nehez-miert-csinaljuk-megis" tabindex="-1"><a class="header-anchor" href="#ha-dependency-injection-nehez-miert-csinaljuk-megis" aria-hidden="true">#</a> Ha <code>Dependency Injection</code> nehéz, miért csináljuk mégis?</h3><p>Csak egy pillanatra álljunk meg, hogy átbeszéljük, miért jó ötlet ez (<em>ha már meggyőztelek, ugorj tovább</em>). Arra kérlek, hogy tegyél a kódodba most egy kis bonyolultságot és bízz bennem, hogy ez javítani fogja az alkalmazásodat.</p><p>Szóval, hogy fogjuk ezt csinálni?!</p><p>Gyakran vannak különböző nézetek különböző okokból - felhasználói bejelentkezések, ügyfélinformációk, bevásárlókosarak, stb.<br> Bármi legyen is, azt szeretnénk, hogy a felhasználóink nagyszerű élményben részesüljenek, lehetővé téve számukra, hogy könnyedén váltogathassanak a különböző nézetek között.</p><p>Például egy jó használati eset lehetőséget ad nekik arra, hogy a bevásárlókosárból elindíthassanak egy másik felhasználói nézetet.</p><p>A <code>shoppingCart.java</code> - <em>a hívó osztály</em> - segítségével tudjuk betölteni és kitölteni a létrehozott felhasználói részletek nézetét. Tehát betöltjük a nézetet, megkapjuk a vezérlőt, és gyorsan írunk néhány kódot a <code>shoppingCart.java</code> fájlba annak érdekében, hogy lekérdezzük a felhasználó adatait az adatbázisból.</p><figure><img src="`+l+'" alt="Amennyiben még nem találkoztál korábban szekvenciadiagrammal, a legfelső résztől halad egyre lejebb. Először meghívjuk a  metódust a -en, ami létrehozza az alapértelmezett vezérlőt, majd megkapjuk a vezérlőt vissza, és így tovább." tabindex="0" loading="lazy"><figcaption>Amennyiben még nem találkoztál korábban szekvenciadiagrammal, a legfelső résztől halad egyre lejebb. Először meghívjuk a <code>load()</code> metódust a <code>FXMLLoader</code>-en, ami létrehozza az alapértelmezett vezérlőt, majd megkapjuk a vezérlőt vissza, és így tovább.</figcaption></figure><p>Két nappal később a <code>wishList.java</code> fájlt kódoljuk, amely egy kívánságlistát jelenít meg, és azt szeretnénk, ha ez a felhasználói nézetet is betöltené. Hirtelen kénytelenek vagyunk az összes adatbázis kódot bemásolni és beilleszteni a <code>wishList.java</code> fájlba.</p><p>Minden új nézetnél, amelynek szüksége van erre a funkcióra, újra be kell másolnunk és be kell illesztenünk a kódot.</p><h3 id="encap" tabindex="-1"><a class="header-anchor" href="#encap" aria-hidden="true">#</a> Encap</h3><p>Jobb megközelítés, ha az <code>FXMLLoader</code> számára biztosítjuk a szükséges eszközöket, hogy maga töltse fel a vezérlőt (és a nézetet). Őszintén szólva, a hívó osztálynak eleve nem lett volna szabad a felhasználói adatok betöltéséért felelősnek lennie. Ezután tetszőleges módon létrehozhatjuk a felhasználói nézetet, és nem kell másolnunk ezt a kódot.</p><p>A jobb megközelítés az, hogy biztosítjuk a <code>FXMLLoader</code> számára a szükséges eszközöket, amelyekkel képes a <code>Controller</code> (és a <code>View</code>) maga kitölteni. Őszintén szólva, a hívó osztálynak eleve nem kellett volna a felelősségét viselnie a felhasználói adatok betöltésére. Ezután létrehozhatjuk a felhasználói nézetet számos módon, és nem kell ezt a kódot másolnunk.</p>',23),i=[o];function k(r,z){return a(),n("div",null,i)}const c=e(s,[["render",k],["__file","lesson3dp.html.vue"]]);export{c as default};
